export interface ComicPage {
  id: number;
  narration: string;
  dialogue: string;
  illustrationPrompt: string;
  imageUrl?: string;
  audioData?: string;
}

export interface ComicStory {
  title: string;
  pages: ComicPage[];
}

export enum AppStatus {
  IDLE = 'IDLE',
  GENERATING_STORY = 'GENERATING_STORY',
  GENERATING_IMAGES = 'GENERATING_IMAGES',
  READY = 'READY',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { ComicStory } from "../types";

const API_KEY = process.env.API_KEY || '';

export const generateComicStory = async (topic: string): Promise<ComicStory> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const prompt = `Create a short, 4-page fun adventure comic book story for a 4-year-old child. 
  The main characters are "Pete the Cat" (a cool, calm blue cat) and "Peppa Pig" (a cheerful pig in a red dress).
  Theme: ${topic}.
  The response must be in JSON format. Each page should have a narration sentence, a short dialogue line, and a detailed prompt for an image generator.

  Guidelines for illustration prompts:
  - Describe Pete the Cat as: "a simple, stylized cool blue cat with large white eyes, yellow sneakers, and a calm expression".
  - Describe Peppa Pig as: "a simple, cartoon pink pig wearing a red dress and black shoes, in the style of children's book illustrations".
  - Use bright, vibrant, flat colors.
  - Keep backgrounds simple and friendly.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          pages: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.INTEGER },
                narration: { type: Type.STRING },
                dialogue: { type: Type.STRING },
                illustrationPrompt: { type: Type.STRING },
              },
              required: ["id", "narration", "dialogue", "illustrationPrompt"]
            }
          }
        },
        required: ["title", "pages"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generatePanelImage = async (prompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: `${prompt}. Children's book illustration style, high quality, clean lines, bright colors.` }]
    },
    config: {
      imageConfig: {
        aspectRatio: "4:3"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image generated");
};

export const generateNarration = async (text: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Read this story page cheerfully for a 4-year-old: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio generated");
  return base64Audio;
};

// Audio Utilities
export const decodeBase64Audio = (base64: string) => {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

export const playAudio = async (base64Data: string) => {
  const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  const bytes = decodeBase64Audio(base64Data);

  const dataInt16 = new Int16Array(bytes.buffer);
  const numChannels = 1;
  const frameCount = dataInt16.length / numChannels;
  const buffer = audioContext.createBuffer(numChannels, frameCount, 24000);

  const channelData = buffer.getChannelData(0);
  for (let i = 0; i < frameCount; i++) {
    channelData[i] = dataInt16[i] / 32768.0;
  }

  const source = audioContext.createBufferSource();
  source.buffer = buffer;
  source.connect(audioContext.destination);
  source.start();
  return new Promise(resolve => {
    source.onended = resolve;
  });
};

