import React, { useState } from 'react';
import { ComicStory, ComicPage } from '../types';
import { playAudio } from '../services/geminiService';

interface ComicBookProps {
  story: ComicStory;
}

const ComicBook: React.FC<ComicBookProps> = ({ story }) => {
  const [currentPage, setCurrentPage] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);

  const page = story.pages[currentPage];

  const handleNext = () => {
    if (currentPage < story.pages.length - 1) {
      setCurrentPage(currentPage + 1);
    }
  };

  const handlePrev = () => {
    if (currentPage > 0) {
      setCurrentPage(currentPage - 1);
    }
  };

  const handlePlayAudio = async () => {
    if (page.audioData && !isPlaying) {
      setIsPlaying(true);
      await playAudio(page.audioData);
      setIsPlaying(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-8">
      <h1 className="text-4xl md:text-5xl font-comic text-center text-blue-600 mb-8 drop-shadow-md">
        {story.title}
      </h1>

      <div className="bg-white rounded-3xl shadow-2xl overflow-hidden border-8 border-white">
        {/* Comic Panel */}
        <div className="relative aspect-[4/3] bg-gray-100 flex items-center justify-center overflow-hidden">
          {page.imageUrl ? (
            <img 
              src={page.imageUrl} 
              alt={`Page ${currentPage + 1}`} 
              className="w-full h-full object-cover transition-opacity duration-500"
            />
          ) : (
            <div className="animate-pulse flex flex-col items-center text-gray-400">
              <svg className="w-20 h-20 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
              </svg>
              <span>Drawing your picture...</span>
            </div>
          )}

          {/* Page Number Badge */}
          <div className="absolute top-4 right-4 bg-yellow-400 text-yellow-900 font-comic px-4 py-1 rounded-full text-lg shadow-sm">
            {currentPage + 1} / {story.pages.length}
          </div>
        </div>

        {/* Text Area */}
        <div className="p-6 bg-blue-50 space-y-4">
          <p className="text-xl md:text-2xl font-semibold text-gray-800 italic leading-relaxed text-center">
            "{page.narration}"
          </p>

          {page.dialogue && (
            <div className="flex justify-center">
              <div className="relative bg-white p-4 rounded-2xl shadow-sm border-2 border-gray-100 max-w-sm">
                <div className="absolute -top-2 left-1/2 -translate-x-1/2 w-4 h-4 bg-white border-t-2 border-l-2 border-gray-100 rotate-45"></div>
                <p className="text-lg text-blue-800 font-bold text-center">
                  {page.dialogue}
                </p>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Controls */}
      <div className="mt-8 flex flex-wrap items-center justify-between gap-4">
        <button
          onClick={handlePrev}
          disabled={currentPage === 0}
          className={`px-8 py-4 rounded-full font-comic text-xl shadow-lg transition-all active:scale-95 flex items-center gap-2 ${
            currentPage === 0 
              ? 'bg-gray-200 text-gray-400 cursor-not-allowed' 
              : 'bg-white text-blue-500 hover:bg-blue-50'
          }`}
        >
          <span>←</span> Back
        </button>

        <button
          onClick={handlePlayAudio}
          disabled={isPlaying || !page.audioData}
          className={`flex-1 md:flex-none px-12 py-4 rounded-full font-comic text-xl shadow-lg transition-all active:scale-95 flex items-center justify-center gap-3 ${
            isPlaying || !page.audioData
              ? 'bg-gray-200 text-gray-400 cursor-not-allowed'
              : 'bg-yellow-400 text-yellow-900 hover:bg-yellow-300'
          }`}
        >
          {isPlaying ? (
            <>
              <div className="w-6 h-6 border-4 border-yellow-900 border-t-transparent rounded-full animate-spin"></div>
              Reading...
            </>
          ) : (
            <>
              <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20">
                <path d="M11 3a1 1 0 011 1v12a1 1 0 01-1 1H9a1 1 0 01-1-1V4a1 1 0 011-1h2zM5 8a1 1 0 011-1h.01a1 1 0 110 2H6a1 1 0 01-1-1zM15 8a1 1 0 110 2h-.01a1 1 0 110-2H15z" />
              </svg>
              Read To Me!
            </>
          )}
        </button>

        <button
          onClick={handleNext}
          disabled={currentPage === story.pages.length - 1}
          className={`px-8 py-4 rounded-full font-comic text-xl shadow-lg transition-all active:scale-95 flex items-center gap-2 ${
            currentPage === story.pages.length - 1
              ? 'bg-gray-200 text-gray-400 cursor-not-allowed'
              : 'bg-blue-600 text-white hover:bg-blue-700'
          }`}
        >
          Next <span>→</span>
        </button>
      </div>
    </div>
  );
};

export default ComicBook;

import React, { useState, useEffect } from 'react';
import { AppStatus, ComicStory, ComicPage } from './types';
import { generateComicStory, generatePanelImage, generateNarration } from './services/geminiService';
import ComicBook from './components/ComicBook';
import Loader from './components/Loader';

const ADVENTURE_IDEAS = [
  "A Space Adventure to Mars",
  "A Trip to the Sunny Beach",
  "Finding Treasure in the Jungle",
  "Exploring the Dinosaur World",
  "A Rainy Day Muddy Puddle Fun"
];

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [story, setStory] = useState<ComicStory | null>(null);
  const [topic, setTopic] = useState("");
  const [error, setError] = useState<string | null>(null);

  const startCreation = async (selectedTopic: string) => {
    try {
      setStatus(AppStatus.GENERATING_STORY);
      setError(null);

      // 1. Generate the Story Structure
      const newStory = await generateComicStory(selectedTopic);
      setStory(newStory);

      // 2. Generate Images and Audio concurrently
      setStatus(AppStatus.GENERATING_IMAGES);

      const updatedPages = [...newStory.pages];

      // We'll update the state progressively as panels arrive
      for (let i = 0; i < updatedPages.length; i++) {
        const page = updatedPages[i];

        // Generate Image
        const imageUrl = await generatePanelImage(page.illustrationPrompt);

        // Generate Audio (Narration + Dialogue)
        const narrationText = `${page.narration}. ${page.dialogue}`;
        const audioData = await generateNarration(narrationText);

        updatedPages[i] = { ...page, imageUrl, audioData };

        // Update story state so the user sees progress (even if they can't see the book yet)
        setStory(prev => prev ? { ...prev, pages: [...updatedPages] } : null);
      }

      setStatus(AppStatus.READY);
    } catch (err: any) {
      console.error(err);
      setError("Oops! Something went wrong. Let's try again!");
      setStatus(AppStatus.IDLE);
    }
  };

  const handleCustomSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (topic.trim()) {
      startCreation(topic);
    }
  };

  return (
    <div className="min-h-screen pb-20">
      {/* Header */}
      <header className="bg-white shadow-sm p-6 mb-8 text-center">
        <h1 className="text-3xl font-comic text-blue-600 tracking-tight">
          Pete & Peppa's <span className="text-pink-500">Magic Comic!</span>
        </h1>
      </header>

      <main className="container mx-auto px-4 max-w-4xl">
        {status === AppStatus.IDLE && (
          <div className="bg-white p-8 rounded-3xl shadow-xl border-4 border-blue-100">
            <h2 className="text-3xl font-comic text-center mb-8 text-gray-800">
              Where should we go today?
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
              {ADVENTURE_IDEAS.map((idea) => (
                <button
                  key={idea}
                  onClick={() => startCreation(idea)}
                  className="p-6 text-left rounded-2xl bg-blue-50 border-2 border-transparent hover:border-blue-400 hover:bg-blue-100 transition-all group"
                >
                  <span className="text-lg font-bold text-blue-800 group-hover:text-blue-900">
                    {idea}
                  </span>
                </button>
              ))}
            </div>

            <form onSubmit={handleCustomSubmit} className="relative">
              <input
                type="text"
                placeholder="Or type your own adventure..."
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                className="w-full p-6 pr-32 rounded-2xl bg-gray-50 border-2 border-gray-200 focus:outline-none focus:ring-4 focus:ring-blue-100 focus:border-blue-400 text-lg transition-all"
              />
              <button
                type="submit"
                className="absolute right-2 top-2 bottom-2 px-6 rounded-xl bg-blue-600 text-white font-bold hover:bg-blue-700 transition-colors"
              >
                Go!
              </button>
            </form>

            {error && (
              <p className="mt-4 text-center text-red-500 font-bold bg-red-50 p-3 rounded-lg">
                {error}
              </p>
            )}
          </div>
        )}

        {(status === AppStatus.GENERATING_STORY || status === AppStatus.GENERATING_IMAGES) && (
          <div className="bg-white rounded-3xl shadow-xl p-12 min-h-[400px] flex flex-col items-center justify-center">
            <Loader 
              message={status === AppStatus.GENERATING_STORY 
                ? "Thinking of a fun story for you..." 
                : "Drawing the pictures! This is magic!"} 
            />
            {status === AppStatus.GENERATING_IMAGES && story && (
              <div className="w-full max-w-md mt-8 bg-gray-100 rounded-full h-4 overflow-hidden">
                <div 
                  className="bg-blue-500 h-full transition-all duration-500" 
                  style={{ width: `${(story.pages.filter(p => p.imageUrl).length / story.pages.length) * 100}%` }}
                ></div>
              </div>
            )}
          </div>
        )}

        {status === AppStatus.READY && story && (
          <div className="animate-in fade-in zoom-in duration-700">
            <ComicBook story={story} />

            <div className="mt-12 flex justify-center">
              <button
                onClick={() => setStatus(AppStatus.IDLE)}
                className="px-10 py-4 bg-white border-4 border-pink-200 text-pink-600 rounded-full font-comic text-xl hover:bg-pink-50 transition-all active:scale-95 shadow-lg"
              >
                Make Another Story!
              </button>
            </div>
          </div>
        )}
      </main>

      {/* Characters Decorative Floating Icons */}
      <div className="fixed bottom-4 left-4 w-24 h-24 md:w-32 md:h-32 opacity-80 pointer-events-none select-none">
        <div className="w-full h-full bg-blue-400 rounded-full flex items-center justify-center text-white text-4xl font-comic shadow-lg border-4 border-white">
          Pete
        </div>
      </div>
      <div className="fixed bottom-4 right-4 w-24 h-24 md:w-32 md:h-32 opacity-80 pointer-events-none select-none">
        <div className="w-full h-full bg-pink-400 rounded-full flex items-center justify-center text-white text-4xl font-comic shadow-lg border-4 border-white">
          Peppa
        </div>
      </div>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { ComicStory } from "../types";

const API_KEY = process.env.API_KEY || '';

export const generateComicStory = async (topic: string): Promise<ComicStory> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const prompt = `Create a high-quality, narrative-driven 4-page adventure comic book story for a 4-year-old child.

  Characters:
  1. Pete the Cat: A super cool, calm blue cat who loves his yellow sneakers. He never gets upset, even when things go wrong. He is groovy and positive.
  2. Peppa Pig: A cheerful, energetic pink pig in a red dress. She loves jumping in muddy puddles and is very curious.

  Theme: ${topic}.

  Story Structure (Must follow this arc):
  - Page 1: Introduction. Pete and Peppa meet up and decide to go on an adventure related to the theme.
  - Page 2: The Adventure Begins. They encounter a small challenge or see something amazing.
  - Page 3: The Climax. They work together using their unique personalities (Pete's calm vs. Peppa's energy) to solve a problem or reach their goal.
  - Page 4: Conclusion. They celebrate their success, perhaps with a "groovy" comment from Pete and a happy snort or puddle jump from Peppa.

  Each page must include:
  - A 'narration' sentence that describes the action clearly for a parent reading aloud.
  - A 'dialogue' line that sounds like the characters (Pete should say things like "It's all good" or "Groovy", Peppa should be excited).
  - A detailed 'illustrationPrompt' that ensures visual consistency.

  Guidelines for illustration prompts:
  - Describe Pete as: "a simple, stylized cool blue cat with large white eyes, yellow sneakers, and a calm, half-lidded expression".
  - Describe Peppa as: "a simple, cartoon pink pig wearing a red dress and black shoes, in the style of children's book illustrations".
  - Maintain a consistent "children's picture book" aesthetic: bright, flat colors, clean outlines, and simple backgrounds.
  - Ensure BOTH characters are present in every frame to show their friendship.

  The response MUST be valid JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          pages: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.INTEGER },
                narration: { type: Type.STRING },
                dialogue: { type: Type.STRING },
                illustrationPrompt: { type: Type.STRING },
              },
              required: ["id", "narration", "dialogue", "illustrationPrompt"]
            }
          }
        },
        required: ["title", "pages"]
      }
    }
  });

  return JSON.parse(response.text);
};

