import { GoogleGenAI, Type, Modality } from "@google/genai";
import { ComicStory } from "../types";

const API_KEY = process.env.API_KEY || '';

export const generateComicStory = async (topic: string): Promise<ComicStory> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const prompt = `Create a high-quality, narrative-driven 4-page adventure comic book story for a 4-year-old child.

  Characters:
  1. Pete the Cat: A super cool, calm dark blue cat who loves his big white sneakers. He never gets upset, even when things go wrong. He is groovy and positive.
  2. Peppa Pig: A cheerful, energetic pink pig in a red dress. She loves jumping in muddy puddles and is very curious.

  Theme: ${topic}.

  Story Structure:
  - Page 1: Introduction. Pete and Peppa meet up and decide to go on an adventure related to the theme.
  - Page 2: The Adventure Begins. They encounter a small challenge or see something amazing.
  - Page 3: The Climax. They work together using their unique personalities (Pete's calm vs. Peppa's energy) to solve a problem or reach their goal.
  - Page 4: Conclusion. They celebrate their success with a positive message.

  Character Appearance & Style:
  - Pete the Cat MUST look like: "A dark indigo-blue cat with large almond-shaped white eyes with amber/yellow centers, long whiskers, and a cool, calm expression. He wears big, chunky white sneakers."
  - Peppa Pig MUST look like: "A simple, cartoon pink pig wearing a red dress and black shoes, but drawn in a sketchy, artistic children's book style to match Pete."
  - Art Style: "Whimsical children's book illustration, watercolor and ink style with visible crayon-like textures, soft hand-drawn lines, on a light-textured paper background. Bright but slightly muted artistic colors."

  Each page must include:
  - A 'narration' sentence that describes the action clearly.
  - A 'dialogue' line (Pete: "Groovy", "It's all good"; Peppa: "Oink! How exciting!").
  - A detailed 'illustrationPrompt' combining the characters and the setting in the style above.

  The response MUST be valid JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          pages: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.INTEGER },
                narration: { type: Type.STRING },
                dialogue: { type: Type.STRING },
