  const [story, setStory] = useState<ComicStory | null>(null);
  const [topic, setTopic] = useState("");
  const [error, setError] = useState<string | null>(null);

  const startCreation = async (selectedTopic: string) => {
    try {
      setStatus(AppStatus.GENERATING_STORY);
      setError(null);

      // 1. Generate the Story Structure
      const newStory = await generateComicStory(selectedTopic);
      setStory(newStory);

      // 2. Generate Images and Audio concurrently
      setStatus(AppStatus.GENERATING_IMAGES);

      const updatedPages = [...newStory.pages];

      // We'll update the state progressively as panels arrive
      for (let i = 0; i < updatedPages.length; i++) {
        const page = updatedPages[i];

        // Generate Image
        const imageUrl = await generatePanelImage(page.illustrationPrompt);

        // Generate Audio (Narration + Dialogue)
        const narrationText = `${page.narration}. ${page.dialogue}`;
        const audioData = await generateNarration(narrationText);

        updatedPages[i] = { ...page, imageUrl, audioData };

