import { GoogleGenAI, Type, Modality } from "@google/genai";
import { ComicStory } from "../types";

const CHARACTER_BLUEPRINTS = {
  pete: "Pete the Cat: A dark indigo-blue cat with a thin frame, large white almond-shaped eyes with amber-yellow centers, 4 long thin whiskers, a long thin blue tail, and always wearing oversized chunky bright white sneakers.",
  peppa: "Peppa Pig: A simple pink cartoon pig with a long snout, two pink circles for nostrils, wearing a solid red sleeveless dress and small black shoes, drawn in a flat but sketchy artistic style."
};

const ART_STYLE = "Artistic children's book illustration style, watercolor and ink sketch, visible crayon-like texture, soft hand-drawn lines, simple charming backgrounds, white textured paper background, whimsical and friendly.";

/**
 * Generates a structured comic story using Gemini.
 */
export const generateComicStory = async (topic: string): Promise<ComicStory> => {
  // Always use process.env.API_KEY directly and create instance before call.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Create a high-quality, narrative-driven 4-page adventure comic book story for a 4-year-old child.

  Characters:
  1. Pete the Cat: Cool, calm, positive.
  2. Peppa Pig: Excited, curious.

  Theme: ${topic}.

  For each page, also provide 2 interactive 'hotspots'. These are coordinates (x, y as percentage 0-100) where a child can tap to see a sparkle. 
  Assign one hotspot to Pete and one to Peppa or an important object in the scene.

  CRITICAL VISUAL RULES:
  - Pete: ${CHARACTER_BLUEPRINTS.pete}
  - Peppa: ${CHARACTER_BLUEPRINTS.peppa}
  - Style: ${ART_STYLE}

  The response MUST be valid JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          pages: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.INTEGER },
                narration: { type: Type.STRING },
                dialogue: { type: Type.STRING },
                illustrationPrompt: { type: Type.STRING },
                hotspots: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      x: { type: Type.NUMBER },
                      y: { type: Type.NUMBER },
                      label: { type: Type.STRING },
                      reaction: { type: Type.STRING }
                    },
                    required: ["x", "y", "label", "reaction"]
                  }
                }
              },
              required: ["id", "narration", "dialogue", "illustrationPrompt", "hotspots"]
            }
          }
        },
        required: ["title", "pages"]
      }
    }
  });

  // Access text directly from property
  const text = response.text || "{}";
  return JSON.parse(text.trim());
};

/**
 * Generates an image for a single panel.
 */
export const generatePanelImage = async (prompt: string): Promise<string> => {
  // Create instance right before API call.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const refinedPrompt = `Characters: ${CHARACTER_BLUEPRINTS.pete} and ${CHARACTER_BLUEPRINTS.peppa}. Scene: ${prompt}. Style: ${ART_STYLE}`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: refinedPrompt }] },
    config: { imageConfig: { aspectRatio: "4:3" } }
  });

  // Iterate through parts to find the image part as per guidelines.
  const parts = response.candidates?.[0]?.content?.parts || [];
  for (const part of parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image generated");
};

/**
 * Generates narration audio using Gemini TTS.
 */
export const generateNarration = async (text: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Narrate cheerfully for a toddler. Pete is cool/relaxed, Peppa is energetic. Text: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio generated");
  return base64Audio;
};

/**
 * Manual Base64 decoding implementation.
 */
export const decodeBase64Audio = (base64: string) => {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

/**
 * Plays raw PCM audio data.
 */
export const playAudio = async (base64Data: string) => {
  const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  const bytes = decodeBase64Audio(base64Data);
  const dataInt16 = new Int16Array(bytes.buffer);
  const buffer = audioContext.createBuffer(1, dataInt16.length, 24000);
  const channelData = buffer.getChannelData(0);
  for (let i = 0; i < dataInt16.length; i++) {
    channelData[i] = dataInt16[i] / 32768.0;
  }
  const source = audioContext.createBufferSource();
  source.buffer = buffer;
  source.connect(audioContext.destination);
  source.start();
  return new Promise((resolve) => {
    source.onended = resolve;
  });
};

/**
 * Plays a simple synthetic sparkle sound.
 */
export const playSparkleSound = () => {
  const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
  const osc = audioContext.createOscillator();
  const gain = audioContext.createGain();
  osc.type = 'triangle';
  osc.frequency.setValueAtTime(800, audioContext.currentTime);
  osc.frequency.exponentialRampToValueAtTime(1200, audioContext.currentTime + 0.1);
  gain.gain.setValueAtTime(0.1, audioContext.currentTime);
  gain.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + 0.2);
  osc.connect(gain);
  gain.connect(audioContext.destination);
  osc.start();
  osc.stop(audioContext.currentTime + 0.2);
};

import React, { useState, useEffect } from 'react';
import { ComicStory, Hotspot } from '../types';
import { playAudio, playSparkleSound } from '../services/geminiService';

interface ComicBookProps {
  story: ComicStory;
}

const SparkleEffect: React.FC<{ x: number; y: number; onComplete: () => void }> = ({ x, y, onComplete }) => {
  useEffect(() => {
    const timer = setTimeout(onComplete, 800);
    return () => clearTimeout(timer);
  }, [onComplete]);

  return (
    <div 
      className="absolute pointer-events-none z-50 animate-ping text-3xl"
      style={{ left: `${x}%`, top: `${y}%`, transform: 'translate(-50%, -50%)' }}
    >
      ✨
    </div>
  );
};

const ComicBook: React.FC<ComicBookProps> = ({ story }) => {
  const [currentPage, setCurrentPage] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [sparkles, setSparkles] = useState<{ id: number; x: number; y: number }[]>([]);
  const [isTransitioning, setIsTransitioning] = useState(false);

  const page = story.pages[currentPage];

  const triggerTransition = (nextPageIdx: number) => {
    setIsTransitioning(true);
    setTimeout(() => {
      setCurrentPage(nextPageIdx);
      setIsTransitioning(false);
    }, 400);
  };

  const handleNext = () => {
    if (currentPage < story.pages.length - 1 && !isTransitioning) {
      triggerTransition(currentPage + 1);
    }
  };

  const handlePrev = () => {
    if (currentPage > 0 && !isTransitioning) {
      triggerTransition(currentPage - 1);
    }
  };

  const handlePlayAudio = async () => {
    if (page.audioData && !isPlaying) {
      setIsPlaying(true);
      try {
        await playAudio(page.audioData);
      } catch (err) {
        console.error("Audio playback error:", err);
      } finally {
        setIsPlaying(false);
      }
    }
  };

  const handleHotspotClick = (hs: Hotspot) => {
    playSparkleSound();
    const newSparkle = { id: Date.now(), x: hs.x, y: hs.y };
    setSparkles(prev => [...prev, newSparkle]);
  };

  const downloadImage = () => {
    if (!page.imageUrl) return;

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      canvas.width = img.width;
      canvas.height = img.height + 450;

      // Background
      ctx.fillStyle = "#ffffff";
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Main Comic Panel
      ctx.drawImage(img, 0, 0);

      // Title
      ctx.save();
      ctx.fillStyle = "#1e40af";
      ctx.font = "bold 60px sans-serif";
      ctx.textAlign = "center";
      ctx.textBaseline = "top";
      ctx.fillText(story.title, canvas.width / 2, img.height + 50);
      ctx.restore();

      // Page Number Circle
      ctx.save();
      ctx.fillStyle = "#fbbf24";
      ctx.beginPath();
      ctx.arc(canvas.width - 80, 80, 50, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = "#78350f";
      ctx.font = "bold 50px sans-serif";
      ctx.textAlign = "center";
      ctx.textBaseline = "middle";
      ctx.fillText(`${currentPage + 1}`, canvas.width - 80, 85);
      ctx.restore();

      // Narration Wrap
      ctx.save();
      ctx.fillStyle = "#000000";
      ctx.font = "italic 36px sans-serif";
      ctx.textAlign = "center";
      ctx.textBaseline = "top";
      const maxWidth = canvas.width - 120;
      const words = page.narration.split(' ');
      let line = '';
      let yLine = img.height + 140;

      for (let n = 0; n < words.length; n++) {
        const testLine = line + words[n] + ' ';
        const metrics = ctx.measureText(testLine);
        if (metrics.width > maxWidth && n > 0) {
          ctx.fillText(line, canvas.width / 2, yLine);
          line = words[n] + ' ';
          yLine += 50;
        } else {
          line = testLine;
        }
      }
      ctx.fillText(line, canvas.width / 2, yLine);
      ctx.restore();

      // Dialogue
      if (page.dialogue) {
        ctx.save();
        const rectY = yLine + 100;
        const dialogueFont = "bold 32px sans-serif";
        ctx.font = dialogueFont;
        const textWidth = ctx.measureText(page.dialogue).width;
        const rectWidth = textWidth + 60;
        const rectHeight = 80;
        const rectX = (canvas.width - rectWidth) / 2;

        ctx.fillStyle = "#f0f9ff";
        ctx.strokeStyle = "#bfdbfe";
        ctx.lineWidth = 4;
        ctx.beginPath();
        if (typeof (ctx as any).roundRect === 'function') {
          (ctx as any).roundRect(rectX, rectY, rectWidth, rectHeight, 20);
        } else {
          ctx.rect(rectX, rectY, rectWidth, rectHeight);
        }
        ctx.fill();
        ctx.stroke();

        ctx.fillStyle = "#000000";
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";
        ctx.fillText(page.dialogue, canvas.width / 2, rectY + (rectHeight / 2));
        ctx.restore();
      }

      // Finalize Download
      const safeTitle = story.title.replace(/[^a-z0-9]/gi, '_').toLowerCase();
      const link = document.createElement('a');
      link.download = `${safeTitle}-page-${currentPage + 1}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    };
    img.src = page.imageUrl;
  };

  const downloadAudio = () => {
    if (!page.audioData) return;
    const binary = atob(page.audioData);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
    const blob = new Blob([bytes], { type: 'audio/pcm' });
    const url = URL.createObjectURL(blob);
    const safeTitle = story.title.replace(/[^a-z0-9]/gi, '_').toLowerCase();
    const link = document.createElement('a');
    link.href = url;
    link.download = `${safeTitle}-audio-page-${currentPage + 1}.pcm`;
    link.click();
    setTimeout(() => URL.revokeObjectURL(url), 100);
  };

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-8">
      <div className="flex flex-col md:flex-row items-center justify-between mb-8 gap-4">
        <h1 className="text-4xl md:text-5xl font-comic text-blue-800 drop-shadow-sm text-center md:text-left">
          {story.title}
        </h1>
        <div className="flex gap-3">
          <button 
            type="button"
            onClick={downloadImage}
            title="Download Page as Image"
            aria-label="Save current page as a picture"
            className="p-3 bg-white border-2 border-blue-100 rounded-full hover:bg-blue-50 transition-all shadow-sm text-blue-600 hover:scale-110 active:scale-95"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
            </svg>
          </button>
          <button 
            type="button"
            onClick={downloadAudio}
            title="Download Narration Audio"
            aria-label="Save narration for this page"
            className="p-3 bg-white border-2 border-blue-100 rounded-full hover:bg-blue-50 transition-all shadow-sm text-blue-600 hover:scale-110 active:scale-95"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
            </svg>
          </button>
        </div>
      </div>

      <div className={`relative bg-white rounded-3xl shadow-2xl overflow-hidden border-8 border-white transition-opacity duration-400 ${isTransitioning ? 'opacity-0' : 'opacity-100'}`}>
        {page.imageUrl ? (
          <div className="relative aspect-[4/3]">
            <img src={page.imageUrl} alt={page.narration} className="w-full h-full object-cover" />

            {/* Hotspots */}
            {page.hotspots?.map((hs, idx) => (
              <button
                key={idx}
                onClick={() => handleHotspotClick(hs)}
                className="absolute w-12 h-12 -translate-x-1/2 -translate-y-1/2 rounded-full border-4 border-white/50 bg-white/20 hover:bg-white/40 transition-colors animate-pulse group"
                style={{ left: `${hs.x}%`, top: `${hs.y}%` }}
