import { GoogleGenAI, Type, Modality } from "@google/genai";
import { ComicStory } from "../types";

const CHARACTER_BLUEPRINTS = {
  pete: "Pete the Cat: A dark indigo-blue cat with a thin frame, large white almond-shaped eyes with amber-yellow centers, 4 long thin whiskers, a long thin blue tail, and always wearing oversized chunky bright white sneakers.",
  peppa: "Peppa Pig: A simple pink cartoon pig with a long snout, two pink circles for nostrils, wearing a solid red sleeveless dress and small black shoes, drawn in a flat but sketchy artistic style."
};

const ART_STYLE = "Artistic children's book illustration style, watercolor and ink sketch, visible crayon-like texture, soft hand-drawn lines, simple charming backgrounds, white textured paper background, whimsical and friendly.";

async function withRetry<T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> {
  try {
    return await fn();
  } catch (error) {
    if (retries > 0) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

function cleanJsonResponse(text: string): string {
  let cleaned = text.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?/, '').replace(/```$/, '');
  }
  return cleaned.trim();
}

/**
 * Analyzes an image to create a character description for consistent generation.
 */
export const describeCharacterImage = async (base64Data: string, mimeType: string): Promise<string> => {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          inlineData: {
            data: base64Data.split(',')[1] || base64Data,
            mimeType: mimeType
          }
        },
        {
          text: "Describe this character for a simple children's book. Focus on colors, basic shapes, and one key accessory. Keep the description concise and descriptive for an illustrator. Example: 'A fluffy orange dog with a blue collar and a wagging tail.'"
        }
      ]
    });
    return response.text || "A friendly mystery character";
  });
};

export const generateComicStory = async (topic: string, guestBlueprint?: string): Promise<ComicStory> => {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const guestInfo = guestBlueprint ? `\n3. Guest Character: ${guestBlueprint}` : "";

    const prompt = `Create a narrative 4-page adventure comic for a 4-year-old.
    Topic: ${topic}.
    Characters:
    1. Pete the Cat (cool, calm)
    2. Peppa Pig (excited, curious)${guestInfo}

    All characters must be included in the adventure.
    Page 1: Meet and start adventure.
    Page 2: Discovery.
    Page 3: Action/Cooperation.
    Page 4: Happy ending.

    For each page: Provide narration, one line of dialogue, an illustration prompt, and 2 interactive hotspots.

    Visual Rules:
    - Pete: ${CHARACTER_BLUEPRINTS.pete}
    - Peppa: ${CHARACTER_BLUEPRINTS.peppa}${guestBlueprint ? `\n- Guest: ${guestBlueprint}` : ""}
    - Style: ${ART_STYLE}

    Return strictly valid JSON.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            pages: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.INTEGER },
                  narration: { type: Type.STRING },
                  dialogue: { type: Type.STRING },
                  illustrationPrompt: { type: Type.STRING },
                  hotspots: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        x: { type: Type.NUMBER },
                        y: { type: Type.NUMBER },
                        label: { type: Type.STRING },
                        reaction: { type: Type.STRING }
                      },
                      required: ["x", "y", "label", "reaction"]
                    }
                  }
                },
                required: ["id", "narration", "dialogue", "illustrationPrompt", "hotspots"]
              }
            }
          },
          required: ["title", "pages"]
        }
      }
    });

    const text = cleanJsonResponse(response.text || "{}");
    const data = JSON.parse(text);
    if (guestBlueprint) data.guestCharacterBlueprint = guestBlueprint;
    return data;
  });
};

export const generatePanelImage = async (prompt: string, guestBlueprint?: string): Promise<string> => {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const guestStr = guestBlueprint ? `, and ${guestBlueprint}` : "";
    const refinedPrompt = `Scene: ${prompt}. Characters: ${CHARACTER_BLUEPRINTS.pete}, ${CHARACTER_BLUEPRINTS.peppa}${guestStr}. Style: ${ART_STYLE}`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: refinedPrompt }] },
      config: { imageConfig: { aspectRatio: "4:3" } }
    });

    const parts = response.candidates?.[0]?.content?.parts || [];
    for (const part of parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image generated");
  });
};

export const generateNarration = async (text: string): Promise<string> => {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Narrate cheerfully for a toddler. Text: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio generated");
    return base64Audio;
  });
};

export const decodeBase64Audio = (base64: string) => {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

export const playSparkleSound = () => {
  try {
    const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
    const osc = audioContext.createOscillator();
    const gain = audioContext.createGain();
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(800, audioContext.currentTime);
    osc.frequency.exponentialRampToValueAtTime(1200, audioContext.currentTime + 0.1);
    gain.gain.setValueAtTime(0.1, audioContext.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + 0.2);
    osc.connect(gain);
    gain.connect(audioContext.destination);
    osc.start();
    osc.stop(audioContext.currentTime + 0.2);
  } catch (e) {
    console.warn("Could not play sparkle sound", e);
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { ComicStory, Hotspot } from '../types';
import { playSparkleSound, decodeBase64Audio } from '../services/geminiService';
import { jsPDF } from 'https://esm.sh/jspdf@2.5.1';

interface ComicBookProps {
  story: ComicStory;
}

const SparkleEffect: React.FC<{ x: number; y: number; onComplete: () => void }> = ({ x, y, onComplete }) => {
  useEffect(() => {
    const timer = setTimeout(onComplete, 800);
    return () => clearTimeout(timer);
  }, [onComplete]);

  return (
    <div 
      className="absolute pointer-events-none z-50 animate-ping text-3xl"
      style={{ left: `${x}%`, top: `${y}%`, transform: 'translate(-50%, -50%)' }}
    >
      ✨
    </div>
  );
};

const ComicBook: React.FC<ComicBookProps> = ({ story }) => {
  const [currentPage, setCurrentPage] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [sparkles, setSparkles] = useState<{ id: number; x: number; y: number }[]>([]);
  const [isTransitioning, setIsTransitioning] = useState(false);

  const audioCtxRef = useRef<AudioContext | null>(null);
  const sourceRef = useRef<AudioBufferSourceNode | null>(null);

  const page = story.pages[currentPage];

  useEffect(() => {
    stopAudio();
  }, [currentPage]);

  useEffect(() => {
    return () => stopAudio();
  }, []);

  const stopAudio = () => {
    if (sourceRef.current) {
      try {
        sourceRef.current.stop();
      } catch (e) {}
      sourceRef.current = null;
    }
    if (audioCtxRef.current) {
      audioCtxRef.current.close();
      audioCtxRef.current = null;
    }
    setIsPlaying(false);
    setIsPaused(false);
  };

  const triggerTransition = (nextPageIdx: number) => {
    setIsTransitioning(true);
    setTimeout(() => {
      setCurrentPage(nextPageIdx);
      setIsTransitioning(false);
    }, 400);
  };

  const handleNext = () => {
    if (currentPage < story.pages.length - 1 && !isTransitioning) {
      triggerTransition(currentPage + 1);
    }
  };

  const handlePrev = () => {
    if (currentPage > 0 && !isTransitioning) {
      triggerTransition(currentPage - 1);
    }
  };

  const handlePlayAudio = async () => {
    if (!page.audioData) return;

    if (!isPlaying) {
      setIsPlaying(true);
      setIsPaused(false);
      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      audioCtxRef.current = ctx;

      try {
        const bytes = decodeBase64Audio(page.audioData);
        const dataInt16 = new Int16Array(bytes.buffer);
        const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
        const channelData = buffer.getChannelData(0);
        for (let i = 0; i < dataInt16.length; i++) {
          channelData[i] = dataInt16[i] / 32768.0;
        }

        const source = ctx.createBufferSource();
        source.buffer = buffer;
        source.connect(ctx.destination);
        sourceRef.current = source;

        source.onended = () => {
          if (sourceRef.current === source) {
            setIsPlaying(false);
            setIsPaused(false);
            audioCtxRef.current = null;
            sourceRef.current = null;
          }
        };
        source.start();
      } catch (err) {
        console.error("Audio playback error:", err);
        stopAudio();
      }
    } 
    else if (audioCtxRef.current) {
      if (audioCtxRef.current.state === 'running') {
        await audioCtxRef.current.suspend();
        setIsPaused(true);
      } else if (audioCtxRef.current.state === 'suspended') {
        await audioCtxRef.current.resume();
        setIsPaused(false);
      }
    }
  };

  const handleHotspotClick = (hs: Hotspot) => {
    playSparkleSound();
    const newSparkle = { id: Date.now(), x: hs.x, y: hs.y };
    setSparkles(prev => [...prev, newSparkle]);
  };

  const downloadFullStorybookPDF = async () => {
    const doc = new jsPDF({
      orientation: 'landscape',
      unit: 'px',
      format: [800, 600]
    });

    const safeTitle = story.title;

    for (let i = 0; i < story.pages.length; i++) {
      const p = story.pages[i];
      if (i > 0) doc.addPage();

      // Background
      doc.setFillColor(240, 249, 255);
      doc.rect(0, 0, 800, 600, 'F');

      // Image
      if (p.imageUrl) {
        try {
          doc.addImage(p.imageUrl, 'PNG', 40, 40, 720, 360);
        } catch (e) {
          console.error("Failed to add image to PDF", e);
        }
      }

      // Title & Page Number
      doc.setTextColor(30, 64, 175);
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(24);
      doc.text(safeTitle, 40, 30);
      doc.setFontSize(16);
      doc.text(`Page ${i + 1}`, 740, 30);

      // Narration
      doc.setTextColor(0, 0, 0);
      doc.setFont('helvetica', 'italic');
      doc.setFontSize(18);
      const splitText = doc.splitTextToSize(p.narration, 720);
      doc.text(splitText, 40, 430);

      // Dialogue Box
      if (p.dialogue) {
        const dText = `"${p.dialogue}"`;
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(20);
        doc.setTextColor(17, 24, 39);
        const dTextWidth = doc.getTextWidth(dText);

        doc.setFillColor(255, 255, 255);
        doc.setDrawColor(191, 219, 254);
        doc.roundedRect(400 - (dTextWidth / 2) - 20, 520, dTextWidth + 40, 50, 10, 10, 'FD');
        doc.text(dText, 400, 550, { align: 'center' });
      }
    }

    doc.save(`${story.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_storybook.pdf`);
  };

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-8">
      <div className="flex flex-col md:flex-row items-center justify-between mb-8 gap-4">
        <h1 className="text-4xl md:text-5xl font-comic text-blue-800 drop-shadow-sm text-center md:text-left">
          {story.title}
        </h1>
        <div className="flex gap-3">
          <button 
            type="button"
            onClick={downloadFullStorybookPDF}
            title="Download Full Storybook PDF"
            aria-label="Save entire story as a PDF"
            className="flex items-center gap-2 px-4 py-3 bg-white border-2 border-blue-100 rounded-full hover:bg-blue-50 transition-all shadow-sm text-blue-600 hover:scale-105 active:scale-95 font-bold"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
            </svg>
            <span className="hidden sm:inline">Save as PDF</span>
          </button>
        </div>
      </div>

      <div className={`relative bg-white rounded-3xl shadow-2xl overflow-hidden border-8 border-white transition-opacity duration-400 ${isTransitioning ? 'opacity-0' : 'opacity-100'}`}>
        {page.imageUrl ? (
          <div className="relative aspect-[4/3]">
            <img src={page.imageUrl} alt={page.narration} className="w-full h-full object-cover" />

            {page.hotspots?.map((hs, idx) => (
              <button
                key={idx}
                onClick={() => handleHotspotClick(hs)}
                className="absolute w-12 h-12 -translate-x-1/2 -translate-y-1/2 rounded-full border-4 border-white/50 bg-white/20 hover:bg-white/40 transition-colors animate-pulse group"
                style={{ left: `${hs.x}%`, top: `${hs.y}%` }}
                title={hs.label}
              >
                <span className="hidden group-hover:block absolute top-full left-1/2 -translate-x-1/2 mt-2 bg-black/70 text-white text-xs px-2 py-1 rounded whitespace-nowrap">
                  {hs.label}
                </span>
              </button>
            ))}

            {sparkles.map(s => (
              <SparkleEffect key={s.id} x={s.x} y={s.y} onComplete={() => setSparkles(prev => prev.filter(p => p.id !== s.id))} />
            ))}
          </div>
        ) : (
          <div className="aspect-[4/3] bg-gray-100 flex items-center justify-center">
            <p className="text-gray-400 font-comic">Loading Illustration...</p>
          </div>
        )}

        <div className="p-6 md:p-10 bg-blue-50">
          <p className="text-2xl md:text-3xl font-comic text-gray-800 mb-6 leading-relaxed">
            {page.narration}
          </p>

          {page.dialogue && (
            <div className="flex justify-center">
              <div className="bg-white px-8 py-4 rounded-2xl border-2 border-blue-200 shadow-sm relative inline-block">
                <p className="text-xl md:text-2xl font-bold text-blue-900">
                  "{page.dialogue}"
                </p>
                <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-4 h-4 bg-white border-r-2 border-b-2 border-blue-200 rotate-45"></div>
              </div>
            </div>
          )}
        </div>

        <button
          onClick={handlePlayAudio}
          disabled={!page.audioData}
          className={`absolute bottom-4 right-4 p-4 rounded-full shadow-lg transition-all ${
            !page.audioData ? 'bg-gray-200 cursor-not-allowed' : 'bg-pink-500 hover:bg-pink-600 hover:scale-110 active:scale-95'
          }`}
        >
          {isPlaying && !isPaused ? (
            <div className="flex gap-1.5 p-1">
              <div className="w-1.5 h-6 bg-white animate-pulse"></div>
              <div className="w-1.5 h-6 bg-white animate-pulse [animation-delay:0.2s]"></div>
            </div>
          ) : (
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          )}
        </button>
      </div>

      <div className="flex items-center justify-between mt-8">
        <button
          onClick={handlePrev}
          disabled={currentPage === 0}
          className={`px-6 py-3 rounded-xl font-bold transition-all flex items-center gap-2 ${
            currentPage === 0 ? 'text-gray-300' : 'text-blue-600 hover:bg-blue-50'
          }`}
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
            <path fillRule="evenodd" d="M12.707 5.293a1 1 0 010 1.414L9.414 10l3.293 3.293a1 1 0 01-1.414 1.414l-4-4a1 1 0 010-1.414l4-4a1 1 0 011.414 0z" clipRule="evenodd" />
          </svg>
          Back
        </button>

        <span className="font-comic text-xl text-blue-800">
          Page {currentPage + 1} of {story.pages.length}
        </span>

        <button
          onClick={handleNext}
          disabled={currentPage === story.pages.length - 1}
          className={`px-6 py-3 rounded-xl font-bold transition-all flex items-center gap-2 ${
            currentPage === story.pages.length - 1 ? 'text-gray-300' : 'text-blue-600 hover:bg-blue-50'
          }`}
        >
          Next
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
