        {status === AppStatus.IDLE && (
          <div className="bg-white p-8 rounded-3xl shadow-xl border-4 border-blue-100 animate-in slide-in-from-bottom-4 duration-500">
            <h2 className="text-3xl font-comic text-center mb-8 text-gray-800">
              Where should we go today?
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
              {ADVENTURE_IDEAS.map((idea) => (
                <button
                  key={idea}
                  onClick={() => startCreation(idea)}
                  className="p-6 text-left rounded-2xl bg-blue-50 border-2 border-transparent hover:border-blue-400 hover:bg-blue-100 transition-all group"
                >
                  <span className="text-lg font-bold text-blue-800 group-hover:text-blue-900">
                    {idea}
                  </span>
                </button>
              ))}
            </div>

            <form onSubmit={handleCustomSubmit} className="relative mb-12">
              <input
                type="text"
                placeholder="Or type your own adventure..."
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                className="w-full p-6 pr-32 rounded-2xl bg-gray-50 border-2 border-gray-200 focus:outline-none focus:ring-4 focus:ring-blue-100 focus:border-blue-400 text-lg text-black transition-all"
              />
              <button
                type="submit"
                className="absolute right-2 top-2 bottom-2 px-6 rounded-xl bg-blue-800 text-white font-bold hover:bg-blue-900 transition-colors"
              >
                Go!
              </button>
            </form>

            {/* Guest Character Upload */}
            <div className="border-t-2 border-dashed border-blue-100 pt-8 mt-4">
              <h3 className="text-xl font-comic text-blue-800 mb-4 flex items-center gap-2">
                <span className="text-2xl">📸</span> Add a Guest Star?
              </h3>
              <p className="text-gray-500 mb-6 text-sm">Upload a photo of a toy, a person, or a pet to join the adventure!</p>

              {!guestPhoto ? (
                <button
                  onClick={() => fileInputRef.current?.click()}
                  className="w-full py-10 border-4 border-dashed border-gray-200 rounded-2xl hover:bg-gray-50 hover:border-blue-300 transition-all flex flex-col items-center justify-center text-gray-400"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 mb-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                  </svg>
                  <span className="font-bold">Select a Guest Photo</span>
                </button>
              ) : (
                <div className="relative group max-w-xs mx-auto">
                  <img src={guestPhoto} alt="Guest character" className="w-full h-48 object-cover rounded-2xl border-4 border-blue-200 shadow-md" />
                  <button 
                    onClick={() => setGuestPhoto(null)}
                    className="absolute -top-3 -right-3 bg-red-500 text-white p-2 rounded-full shadow-lg hover:bg-red-600 transition-colors"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                    </svg>
                  </button>
                  <div className="mt-2 text-center text-blue-600 font-bold text-sm">Great Guest Character! 🌟</div>
                </div>
              )}
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handlePhotoUpload} 
                className="hidden" 
                accept="image/*"
              />
            </div>

            {error && (
              <div className="mt-6 p-4 bg-red-50 border-2 border-red-200 rounded-2xl text-center">
                <p className="text-red-600 font-bold">{error}</p>
                <button 
                  onClick={() => setError(null)}
                  className="mt-2 text-sm text-red-400 underline"
                >
                  Dismiss
                </button>
              </div>
            )}
          </div>
        )}

        {(status === AppStatus.ANALYZING_CHARACTER || status === AppStatus.GENERATING_STORY || status === AppStatus.GENERATING_IMAGES) && (
          <div className="bg-white rounded-3xl shadow-xl p-12 min-h-[400px] flex flex-col items-center justify-center">
            <Loader 
              message={
                status === AppStatus.ANALYZING_CHARACTER ? "Looking closely at your guest character..." :
                status === AppStatus.GENERATING_STORY ? "Thinking of a fun story for everyone..." : 
                "Drawing the pictures! This is magic!"
              } 
            />
            {status === AppStatus.GENERATING_IMAGES && story && (
              <div className="w-full max-w-md mt-8 bg-gray-100 rounded-full h-4 overflow-hidden">
                <div 
                  className="bg-blue-800 h-full transition-all duration-500" 
                  style={{ width: `${(story.pages.filter(p => p.imageUrl).length / story.pages.length) * 100}%` }}
                ></div>
              </div>
            )}
          </div>
        )}

        {status === AppStatus.READY && story && (
          <div className="animate-in fade-in zoom-in duration-700">
            <ComicBook story={story} />

            <div className="mt-12 flex justify-center">
              <button
                onClick={() => setStatus(AppStatus.IDLE)}
                className="px-10 py-4 bg-white border-4 border-pink-200 text-pink-600 rounded-full font-comic text-xl hover:bg-pink-50 transition-all active:scale-95 shadow-lg"
              >
                Make Another Story!
              </button>
            </div>
          </div>
        )}
      </main>

      <div className="fixed bottom-4 left-4 w-24 h-24 md:w-32 md:h-32 opacity-80 pointer-events-none select-none z-0">
        <div className="w-full h-full bg-[#1e2a5a] rounded-full flex items-center justify-center text-white text-xl md:text-3xl font-comic shadow-lg border-4 border-white">
          Pete
        </div>
      </div>
      <div className="fixed bottom-4 right-4 w-24 h-24 md:w-32 md:h-32 opacity-80 pointer-events-none select-none z-0">
        <div className="w-full h-full bg-pink-400 rounded-full flex items-center justify-center text-white text-xl md:text-3xl font-comic shadow-lg border-4 border-white">
